// ─── STATUS NORMALISATION (CSV is inconsistent) ─────────────
// Maps every raw status seen in the source CSV → canonical key.
const STATUS_MAP = {
  'resolved':       'resolved',
  'in progress':    'progress',
  'inprogress':     'progress',
  'unresolved':     'unresolved',
  'pending':        'unresolved',
  'duplicate':      'duplicate',
};
function canonicalStatus(raw) {
  return STATUS_MAP[String(raw || '').toLowerCase().trim()] || 'unresolved';
}
const STATUS_LABEL = {resolved:'Resolved', progress:'In Progress', unresolved:'Unresolved', duplicate:'Duplicate'};
const STATUS_GLYPH = {resolved:'✅', progress:'⏳', unresolved:'🔴', duplicate:'🪞'};

