// ─── AGE / SLA HELPERS ──────────────────────────────────────
// As pasted by Love: green < 3 days, amber 3–6 days, red ≥ 7 days.
function getAgeDays(createdStr) {
  const created = new Date(createdStr);
  const today = new Date();
  return Math.floor((today - created) / (1000 * 60 * 60 * 24));
}
function getAgeLabel(createdStr) {
  const days = getAgeDays(createdStr);
  if (days <= 0) return '< 1 day';
  return days + (days === 1 ? ' day' : ' days');
}
function getAgeClass(createdStr) {
  const d = getAgeDays(createdStr);
  return d >= 7 ? 'age-red' : d >= 3 ? 'age-amber' : 'age-green';
}

